197→        // binary search for min(arr[l] >= vmin)
198→        var l = 0
199→        while (l < r) {
200→            val m = (r + l) / 2
201→            if (vmax < arr[m]) {
202→                r = m - 1
203→            } else if (arr[m] < vmin) {
204→                l = m + 1
