    @Test
    fun `Given that a NoFooIdentifierRule violation is not suppressed with an EOL-comment ktlint-disable`() {
        val code =
            """
            val foo = "foo" // ktlint-disable
            """.trimIndent()
        assertThat(lint(code)).containsExactly(
            lintError(1, 5, "standard:no-foo-identifier-standard"),
            lintError(1, 5, "$NON_STANDARD_RULE_SET_ID:no-foo-identifier"),
        )
    }

    @Test
    fun `Given that a NoFooIdentifierRule violation is not suppressed with an EOL-comment ktlint-disable for specific rules`() {
        val code =
