        assertThat(lint(code)).containsExactly(
            lintError(6, 9, "standard:no-foo-identifier-standard"),
            lintError(6, 9, "$NON_STANDARD_RULE_SET_ID:no-foo-identifier"),
            lintError(7, 9, "standard:no-foo-identifier-standard"),
            lintError(7, 9, "$NON_STANDARD_RULE_SET_ID:no-foo-identifier"),
        )
    }

    @Nested
    inner class `Given that formatter tags are enabled` {
        @Test
        fun `Given that a NoFooIdentifierRule violation is suppressed with the default formatter tags in a block comment then do not find a violation in that block`() {
            val code =
                """
                /* @formatter:off */
                val fooNotReported = "foo"
                /* @formatter:on */
                val fooReported = "foo"
                """.trimIndent()

            val actual =
                lint(
                    code,
                    editorConfigOverride = EditorConfigOverride.from(FORMATTER_TAGS_ENABLED_PROPERTY to true),
                )
            assertThat(actual).containsExactly(
                lintError(4, 5, "standard:no-foo-identifier-standard"),
                lintError(4, 5, "$NON_STANDARD_RULE_SET_ID:no-foo-identifier"),
            )
        }

        @Test
        fun `Given that a NoFooIdentifierRule violation is suppressed with the default formatter tags in EOL comments then do not find a violation in that block`() {
            val code =
                """
                // @formatter:off
                val fooNotReported = "foo"
                // @formatter:on
                val fooReported = "foo"
                """.trimIndent()

            val actual =
                lint(
                    code,
                    editorConfigOverride = EditorConfigOverride.from(FORMATTER_TAGS_ENABLED_PROPERTY to true),
                )
            assertThat(actual).containsExactly(
                lintError(4, 5, "standard:no-foo-identifier-standard"),
                lintError(4, 5, "$NON_STANDARD_RULE_SET_ID:no-foo-identifier"),
            )
        }

        @Test
        fun `Given that a NoFooIdentifierRule violation is suppressed with custom formatter tags in block comments then do not find a violation in that block`() {
            val code =
                """
                /* custom-formatter-tag-off */
                val fooNotReported = "foo"
                /* custom-formatter-tag-on */
                val fooReported = "foo"
                """.trimIndent()

            val actual =
                lint(
                    code,
                    editorConfigOverride =
                        EditorConfigOverride.from(
                            FORMATTER_TAGS_ENABLED_PROPERTY to true,
                            FORMATTER_TAG_OFF_ENABLED_PROPERTY to "custom-formatter-tag-off",
                            FORMATTER_TAG_ON_ENABLED_PROPERTY to "custom-formatter-tag-on",
                        ),
                )
            assertThat(actual).containsExactly(
                lintError(4, 5, "standard:no-foo-identifier-standard"),
                lintError(4, 5, "$NON_STANDARD_RULE_SET_ID:no-foo-identifier"),
            )
        }

        @Test
        fun `Given that a NoFooIdentifierRule violation is suppressed with custom formatter tags in EOL comments then do not find a violation in that block`() {
            val code =
                """
                // custom-formatter-tag-off
                val fooNotReported = "foo"
                // custom-formatter-tag-on
                val fooReported = "foo"
                """.trimIndent()

            val actual =
                lint(
                    code,
                    editorConfigOverride =
                        EditorConfigOverride.from(
                            FORMATTER_TAGS_ENABLED_PROPERTY to true,
                            FORMATTER_TAG_OFF_ENABLED_PROPERTY to "custom-formatter-tag-off",
                            FORMATTER_TAG_ON_ENABLED_PROPERTY to "custom-formatter-tag-on",
                        ),
                )
            assertThat(actual).containsExactly(
                lintError(4, 5, "standard:no-foo-identifier-standard"),
                lintError(4, 5, "$NON_STANDARD_RULE_SET_ID:no-foo-identifier"),
            )
        }
    }

    private class NoFooIdentifierRule(id: RuleId) : Rule(
        ruleId = id,
        about = About(),
    ) {
        override fun beforeVisitChildNodes(
            node: ASTNode,
            autoCorrect: Boolean,
            emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
        ) {
            if (node.elementType == ElementType.IDENTIFIER && node.text.startsWith("foo")) {
                emit(node.startOffset, "Line should not contain a foo identifier", false)
            }
        }
    }

    private fun lint(
        code: String,
        editorConfigOverride: EditorConfigOverride = EditorConfigOverride.EMPTY_EDITOR_CONFIG_OVERRIDE,
    ) = ArrayList<LintError>().apply {
        KtLintRuleEngine(
            ruleProviders =
                setOf(
                    // The same rule is supplied once a standard rule and once as non-standard rule. Note that the
                    // ruleIds are different.
                    RuleProvider { NoFooIdentifierRule(STANDARD_NO_FOO_IDENTIFIER_RULE_ID) },
                    RuleProvider { NoFooIdentifierRule(NON_STANDARD_NO_FOO_IDENTIFIER_RULE_ID) },
                ),
            editorConfigOverride =
                editorConfigOverride
                    .plus(
                        STANDARD_NO_FOO_IDENTIFIER_RULE_ID.createRuleExecutionEditorConfigProperty() to RuleExecution.enabled,
                        NON_STANDARD_NO_FOO_IDENTIFIER_RULE_ID.createRuleExecutionEditorConfigProperty() to RuleExecution.enabled,
                    ),
        ).lint(Code.fromSnippet(code)) { e -> add(e) }
    }

    private fun lintError(
        line: Int,
        col: Int,
        ruleId: String,
    ) = LintError(line, col, RuleId(ruleId), "Line should not contain a foo identifier", false)

    private companion object {
        val NON_STANDARD_RULE_SET_ID = "custom".also { require(it != RuleSetId.STANDARD.value) }

        val STANDARD_NO_FOO_IDENTIFIER_RULE_ID = RuleId("standard:no-foo-identifier-standard")
        val NON_STANDARD_NO_FOO_IDENTIFIER_RULE_ID = RuleId("$NON_STANDARD_RULE_SET_ID:no-foo-identifier")
    }
}"}

{"file_path":"/project/ktlint-ruleset-standard/src/test/kotlin/com/pinterest/ktlint/ruleset/standard/rules/MaxLineLengthRuleTest.kt","content":"package com.pinterest.ktlint.ruleset.standard.rules

import com.pinterest.ktlint.rule.engine.core.api.editorconfig.MAX_LINE_LENGTH_PROPERTY
import com.pinterest.ktlint.ruleset.standard.rules.MaxLineLengthRule.Companion.IGNORE_BACKTICKED_IDENTIFIER_PROPERTY
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.EOL_CHAR
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.MAX_LINE_LENGTH_MARKER
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import com.pinterest.ktlint.test.LintViolation
import com.pinterest.ktlint.test.MULTILINE_STRING_QUOTE
import org.assertj.core.api.Assertions.assertThat
import org.junit.jupiter.api.Nested
import org.junit.jupiter.api.Test

class MaxLineLengthRuleTest {
    private val maxLineLengthRuleAssertThat = assertThatRule { MaxLineLengthRule() }

    @Test
    fun `Given some code that exceeds the max line length then return a lint error`() {
        val code =
            """
            // $MAX_LINE_LENGTH_MARKER                   $EOL_CHAR
            val fooooooooooooooo = "fooooooooooooooooooooo"
            val foooooooooooooo = "foooooooooooooooooooo" // some comment
            val fooooooooooooo =
                "foooooooooooooooooooooooooooooooooooooooo"
            """.trimIndent()
        maxLineLengthRuleAssertThat(code)
            .setMaxLineLength()
            .hasLintViolationsWithoutAutoCorrect(
                LintViolation(2, 1, "Exceeded max line length (46)"),
                LintViolation(3, 1, "Exceeded max line length (46)"),
                LintViolation(5, 1, "Exceeded max line length (46)"),
            )
    }

    @Nested
    inner class `Given code that exceeds the max line length but for which no lint error should be returned` {
        @Test
        fun `Given a package statement that that exceeds the max line length then do not return a lint error`() {
            val code =
                """
                // $MAX_LINE_LENGTH_MARKER      $EOL_CHAR
                package com.toooooooooooooooo.long
                """.trimIndent()
            maxLineLengthRuleAssertThat(code)
                .setMaxLineLength()
                .hasNoLintViolations()
        }

        @Test
        fun `Given an import statement that that exceeds the max line length then do not return a lint error`() {
            val code =
                """
                // $MAX_LINE_LENGTH_MARKER      $EOL_CHAR
                import com.toooooooooooooooo.long
                """.trimIndent()
            maxLineLengthRuleAssertThat(code)
                .setMaxLineLength()
                .hasNoLintViolations()
        }

        @Test
        fun `Given a multiline string which exceeds the max line length then do not return a lint error`() {
            val code =
                """
                // $MAX_LINE_LENGTH_MARKER      $EOL_CHAR
                val foo =
                    $MULTILINE_STRING_QUOTE
                    foooooooooooooooooooooooooooooooooo
                    $MULTILINE_STRING_QUOTE
                """.trimIndent()
            maxLineLengthRuleAssertThat(code)
                .setMaxLineLength()
                .hasNoLintViolations()
        }

        @Test
        fun `Given a block comment which exceeds the max line length then do not return a lint error`() {
            val code =
                """
                // $MAX_LINE_LENGTH_MARKER      $EOL_CHAR
                /*
                 * This block comment exceeds the max line length
                 */
                """.trimIndent()
            maxLineLengthRuleAssertThat(code)
                .setMaxLineLength()
                .hasNoLintViolations()
        }

        @Test
        fun `Given a KDoc which exceeds the max line length then do not return a lint error`() {
            val code =
                """
                // $MAX_LINE_LENGTH_MARKER      $EOL_CHAR
                /**
                 * This block comment exceeds the max line length
                 */
                """.trimIndent()
            maxLineLengthRuleAssertThat(code)
                .setMaxLineLength()
                .hasNoLintViolations()
        }
    }

    @Test
    fun testLintOff() {
        val code = "// some" + " long ".repeat(100) + "comment" // Total length of line is 7 + 600 + 7 = 614 characters
        maxLineLengthRuleAssertThat(code)
            .withEditorConfigOverride(MAX_LINE_LENGTH_PROPERTY to "off")
            .hasNoLintViolations()
    }

    @Test
    fun testRangeSearch() {
        for (i in 0 until 10) {
            assertThat(RangeTree((0..i).toList()).query(Int.MIN_VALUE, Int.MAX_VALUE).toString())
                .isEqualTo((0..i).toList().toString())
        }
        assertThat(RangeTree(emptyList()).query(1, 5).toString()).isEqualTo("[]")
        assertThat(RangeTree((5 until 10).toList()).query(1, 5).toString()).isEqualTo("[]")
        assertThat(RangeTree((5 until 10).toList()).query(3, 7).toString()).isEqualTo("[5, 6]")
        assertThat(RangeTree((5 until 10).toList()).query(7, 12).toString()).isEqualTo("[7, 8, 9]")
        assertThat(RangeTree((5 until 10).toList()).query(10, 15).toString()).isEqualTo("[]")
        assertThat(RangeTree(listOf(1, 5, 10)).query(3, 4).toString()).isEqualTo("[]")
    }
}"}

{"file_path":"/project/ktlint-ruleset-standard/src/test/kotlin/com/pinterest/ktlint/ruleset/standard/rules/NoSingleLineBlockCommentRuleTest.kt","content":"package com.pinterest.ktlint.ruleset.standard.rules

import com.pinterest.ktlint.rule.engine.core.api.RuleProvider
import com.pinterest.ktlint.rule.engine.core.api.editorconfig.CODE_STYLE_PROPERTY
import com.pinterest.ktlint.rule.engine.core.api.editorconfig.CodeStyleValue
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Nested
import org.junit.jupiter.api.Test

class NoSingleLineBlockCommentRuleTest {
    private val noSingleLineBlockCommentRuleAssertThat =
        assertThatRule(
            provider = { NoSingleLineBlockCommentRule() },
            additionalRuleProviders = setOf(RuleProvider { CommentWrappingRule() }),
            editorConfigProperties = setOf(CODE_STYLE_PROPERTY to CodeStyleValue.ktlint_official),
        )

    @Test
    fun `Given a single line block comment then replace it with an EOL comment`() {
        val code =
            """
            fun bar() {
                /* Some comment */
            }
            """.trimIndent()
        val formattedCode =
            """
            fun bar() {
                // Some comment
            }
            """.trimIndent()
        noSingleLineBlockCommentRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to CodeStyleValue.ktlint_official)
            .hasLintViolation(2, 5, "Replace the block comment with an EOL comment")
            .isFormattedAs(formattedCode)
    }

    @Test
    fun `Given a multi line block comment that start starts and end on a separate line then do not reformat`() {
        val code =
            """
            /*
             * Some comment
             */
            """.trimIndent()
        noSingleLineBlockCommentRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a single line block comment that is to be wrapped before replacing it with an EOL comment`() {
        val code =
            """
            /* Some comment */ val foo = "foo"
            """.trimIndent()
        val formattedCode =
            """
            // Some comment
            val foo = "foo"
            """.trimIndent()
        noSingleLineBlockCommentRuleAssertThat(code)
            .hasLintViolationForAdditionalRule(1, 20, "A block comment may not be followed by any other element on that same line")
            // Can not check for the lint violation below as it will only be thrown while formatting with comment wrapping
            //   A single line block comment must be replaced with an EOL comment
            .isFormattedAs(formattedCode)
    }

    @Nested
    inner class `Given some code code followed by a block comment on the same line` {
        @Test
        fun `Given a comment followed by a property and separated with space`() {
            val code =
                """
                val foo = "foo" /* Some comment */
                """.trimIndent()
            val formattedCode =
                """
                val foo = "foo" // Some comment
                """.trimIndent()
            noSingleLineBlockCommentRuleAssertThat(code)
                .hasLintViolation(1, 17, "Replace the block comment with an EOL comment")
                .isFormattedAs(formattedCode)
        }

        @Test
        fun `Given a comment followed by a property but not separated with space`() {
            val code =
                """
                val foo = "foo"/* Some comment */
                """.trimIndent()
            val formattedCode =
                """
                val foo = "foo" // Some comment
                """.trimIndent()
            @Suppress("ktlint:argument-list-wrapping", "ktlint:max-line-length")
            noSingleLineBlockCommentRuleAssertThat(code)
                .hasLintViolation(1, 16, "Replace the block comment with an EOL comment")
                .isFormattedAs(formattedCode)
        }

        @Test
        fun `Given a comment followed by a function and separated with space`() {
            val code =
                """
                fun foo() = "foo" /* Some comment */
                """.trimIndent()
            val formattedCode =
                """
                fun foo() = "foo" // Some comment
                """.trimIndent()
            @Suppress("ktlint:argument-list-wrapping", "ktlint:max-line-length")
            noSingleLineBlockCommentRuleAssertThat(code)
                .hasLintViolation(1, 19, "Replace the block comment with an EOL comment")
                .isFormattedAs(formattedCode)
        }

        @Test
        fun `Given a comment followed by a function but not separated with space`() {
            val code =
                """
                fun foo() = "foo"/* Some comment */
                """.trimIndent()
            val formattedCode =
                """
                fun foo() = "foo" // Some comment
                """.trimIndent()
            noSingleLineBlockCommentRuleAssertThat(code)
                .hasLintViolation(1, 18, "Replace the block comment with an EOL comment")
                .isFormattedAs(formattedCode)
        }
    }

    @Test
    fun `Given a block comment that does not contain a newline and which is after some code om the same line is changed to an EOL comment`() {
        val code =
            """
            val foo = "foo" /* Some comment */
            """.trimIndent()
        val formattedCode =
            """
            val foo = "foo" // Some comment
            """.trimIndent()
        noSingleLineBlockCommentRuleAssertThat(code)
            .hasLintViolation(1, 17, "Replace the block comment with an EOL comment")
            .isFormattedAs(formattedCode)
    }

    @Test
    fun `Given a single line block comment in between code elements on the same line does not raise a lint error`() {
        val code =
            """
            val foo /* some comment */ = "foo"
            """.trimIndent()
        noSingleLineBlockCommentRuleAssertThat(code).hasNoLintViolationsExceptInAdditionalRules()
    }

    @Test
    fun `Given a single line block containing a block comment then do not reformat`() {
        val code =
            """
            val foo = { /* no-op */ }
            """.trimIndent()
        noSingleLineBlockCommentRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to CodeStyleValue.ktlint_official)
            .hasNoLintViolations()
    }
}"}

